# Base creature module - defines abstract and virtual base class

class Creature:
    name: str
    age: int

    def __init__(self, name: str, age: int):
        self.name = name
        self.age = age

    @virtual
    def speak(self) -> str:
        return "..."

    @virtual
    def describe(self) -> str:
        return f"{self.name} is {self.age} years old"


class MythicalCreature(Creature):
    power: str

    def __init__(self, name: str, age: int, power: str):
        super().__init__(name, age)
        self.power = power

    @override
    def describe(self) -> str:
        base: str = super().describe()
        return f"{base} with power of {self.power}"

