# Creature implementations - imports base and provides concrete types
from creature_base import Creature, MythicalCreature

class Dragon(MythicalCreature):
    wingspan: int

    def __init__(self, name: str, age: int, wingspan: int):
        super().__init__(name, age, "fire")
        self.wingspan = wingspan

    @override
    def speak(self) -> str:
        return "Roar!"

    @override
    def describe(self) -> str:
        base: str = super().describe()
        return f"{base}, wingspan {self.wingspan}m"


class Unicorn(MythicalCreature):
    horn_color: str

    def __init__(self, name: str, age: int, horn_color: str):
        super().__init__(name, age, "healing")
        self.horn_color = horn_color

    @override
    def speak(self) -> str:
        return "Neigh!"

    @override
    def describe(self) -> str:
        base: str = super().describe()
        return f"{base}, {self.horn_color} horn"


@final
class Phoenix(MythicalCreature):
    rebirth_count: int

    def __init__(self, age: int, rebirths: int):
        super().__init__("Fawkes", age, "rebirth")
        self.rebirth_count = rebirths

    @override
    def speak(self) -> str:
        return "Caw!"

    def total_lives(self) -> int:
        return self.rebirth_count + 1
